	private static void validateLocalJoinApplication(CascadesRule rule, MemoExpr logical,
			RuleApplication application) {
		String ruleId = rule == null ? "<unknown>" : rule.id();
		if (application.kind() != RuleKind.IMPLEMENTATION) {
			throw invalidLocalJoinApplication(ruleId, "application kind is " + application.kind());
		}
		if (application.targetGroupId() != logical.groupId()) {
			throw invalidLocalJoinApplication(ruleId, "target group differs from the scoped logical group");
		}
		if (application.opaque()) {
			throw invalidLocalJoinApplication(ruleId, "application is atomic/opaque");
		}
		ScopedMemoInputReference logicalLeft = leftInputReference(logical.tupleExpr());
		ScopedMemoInputReference logicalRight = rightInputReference(logical.tupleExpr());
		ScopedMemoInputReference physicalLeft = leftInputReference(application.alternative());
		ScopedMemoInputReference physicalRight = rightInputReference(application.alternative());
		if (logicalLeft == null || logicalRight == null || physicalLeft == null || physicalRight == null
				|| logical.tupleExpr().getClass() != application.alternative().getClass()
				|| typedOperatorOrigin(logical.tupleExpr()) != typedOperatorOrigin(application.alternative())
				|| logicalLeft.candidateId() != physicalLeft.candidateId()
				|| logicalRight.candidateId() != physicalRight.candidateId()) {
			throw invalidLocalJoinApplication(ruleId,
					"application does not preserve the typed operator and ordered two-input scoped references");
		}
		if (application.inputRequirements().size() != 2
				|| application.inputSemanticRequirements().size() != 2) {
			throw invalidLocalJoinApplication(ruleId, "application does not declare two child contracts");
		}
		JoinEdge.Origin origin = typedOperatorOrigin(logical.tupleExpr());
		if ((origin == JoinEdge.Origin.EXISTS || origin == JoinEdge.Origin.NOT_EXISTS)
				&& !typedExistsInputLayout(logical, application)) {
			throw invalidLocalJoinApplication(ruleId,
					"EXISTS implementation must preserve executable ARGUMENT and semantically compatible SCALAR_SUBQUERY inputs");
		}
		if (!application.inputGroupIds().isEmpty()
				&& !application.inputGroupIds().equals(logical.inputGroupIds())) {
			throw invalidLocalJoinApplication(ruleId, "application rewrites authoritative scoped child groups");
		}
	}

	private static boolean typedExistsInputLayout(MemoExpr logical, RuleApplication application) {
		List<MemoInput> inputs = logical.inputs();
		return inputs.size() == 2
				&& inputs.get(0).role() == MemoInput.Role.ARGUMENT
				&& inputs.get(0).ordinal() == 0
				&& inputs.get(0).use() == MemoInput.Use.EXECUTABLE
				&& inputs.get(1).role() == MemoInput.Role.SCALAR_SUBQUERY
				&& inputs.get(1).ordinal() == 0
				&& inputs.get(1).use() == MemoInput.Use.EXECUTABLE
				&& inputs.get(1).requiredSemanticScope() == SemanticScope.EXISTENCE
				&& application.inputSemanticRequirements()
						.get(1)
						.isAdmissibleFor(inputs.get(1).requiredSemanticScope());
	}

	private static ScopedMemoInputReference leftInputReference(TupleExpr expression) {
		if (expression instanceof Join join && join.getLeftArg()instanceof ScopedMemoInputReference reference) {
			return reference;
		}
		if (expression instanceof Difference difference
				&& difference.getLeftArg()instanceof ScopedMemoInputReference reference) {
			return reference;
		}
		if (expression instanceof LeftJoin leftJoin
				&& leftJoin.getLeftArg()instanceof ScopedMemoInputReference reference) {
			return reference;
		}
		if (expression instanceof Filter filter
				&& filter.getArg()instanceof ScopedMemoInputReference reference) {
			return reference;
		}
		return null;
	}

	private static ScopedMemoInputReference rightInputReference(TupleExpr expression) {
		if (expression instanceof Join join && join.getRightArg()instanceof ScopedMemoInputReference reference) {
			return reference;
		}
		if (expression instanceof Difference difference
				&& difference.getRightArg()instanceof ScopedMemoInputReference reference) {
			return reference;
		}
		if (expression instanceof LeftJoin leftJoin
				&& leftJoin.getRightArg()instanceof ScopedMemoInputReference reference) {
			return reference;
		}
		if (existsSubquery(expression)instanceof ScopedMemoInputReference reference) {
			return reference;
		}
		return null;
	}

	private static TupleExpr existsSubquery(TupleExpr expression) {
		if (!(expression instanceof Filter filter)) {
			return null;
		}
		if (filter.getCondition()instanceof Exists exists) {
			return exists.getSubQuery();
		}
		if (filter.getCondition()instanceof Not not && not.getArg()instanceof Exists exists) {
			return exists.getSubQuery();
		}
		return null;
	}

	private static JoinEdge.Origin typedOperatorOrigin(TupleExpr expression) {
		if (expression instanceof LeftJoin) {
			return JoinEdge.Origin.LEFT_JOIN;
		}
		if (expression instanceof Difference) {
			return JoinEdge.Origin.MINUS;
		}
		if (expression instanceof Join) {
			return JoinEdge.Origin.INNER_JOIN;
		}
		if (expression instanceof Filter filter) {
			if (filter.getCondition() instanceof Exists) {
				return JoinEdge.Origin.EXISTS;
			}
			if (filter.getCondition()instanceof Not not && not.getArg() instanceof Exists) {
				return JoinEdge.Origin.NOT_EXISTS;
			}
		}
		return null;
	}

	private static IllegalArgumentException invalidLocalJoinApplication(String ruleId, String reason) {
		return new IllegalArgumentException("Registered scoped JOIN implementation " + ruleId + " rejected: " + reason);
	}

